from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/firstaid')
def firstaid():
    symptoms = request.args.get('symptoms')

    treatment = {
        'Cuts': 'Clean wound, apply antiseptic, bandage.',
        'Sprains': 'RICE - Rest, Ice, Compression, Elevation.',
        'Burns': 'Cool burn under running water, cover with sterile dressing.'
    }

    response = {
        'symptom': symptoms,
        'treatment': treatment[symptoms]
    }

    html = "<p>{}</p>".format(response['treatment'])
    return html
